<!doctype html>
<html><head><meta charset="utf-8"><title>Handover Form</title><style>body{font-family:Arial,sans-serif;color:#111;margin:36px}.doc{max-width:820px;margin:auto}.head{display:flex;justify-content:space-between;border-bottom:2px solid #111;padding-bottom:16px}.grid{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin:24px 0}.box{border:1px solid #ccc;padding:12px}.sign{display:grid;grid-template-columns:1fr 1fr;gap:48px;margin-top:80px}.line{border-top:1px solid #111;padding-top:8px}@media print{button{display:none}}</style></head>
<body onload="window.print()"><div class="doc"><button onclick="window.print()">Print</button><div class="head"><h1>Asset Handover Form</h1><strong>#{{ $assignment->id }}</strong></div>
<div class="grid"><div class="box"><strong>Employee</strong><br>{{ $assignment->employee?->name_en }}<br>{{ $assignment->employee?->employee_code }}<br><span dir="rtl">{{ $assignment->employee?->name_ar }}</span></div><div class="box"><strong>Asset</strong><br>{{ $assignment->asset?->asset_tag }} - {{ $assignment->asset?->name }}<br>Serial: {{ $assignment->asset?->serial_number ?: '-' }}<br>Brand: {{ $assignment->asset?->brand?->name ?? '-' }}</div><div class="box"><strong>Handover Date</strong><br>{{ $assignment->handover_date?->format('M d, Y') }}</div><div class="box"><strong>Expected Return</strong><br>{{ $assignment->expected_return_date?->format('M d, Y') ?: '-' }}</div></div>
<p>{{ $assignment->handover_notes }}</p><div class="sign"><div class="line">Employee Signature</div><div class="line">Authorized Signature</div></div></div></body></html>
